theorem regularizedKernelMatrix_symmetric {n : ℕ}
    (K : Matrix (Fin n) (Fin n) ℝ) (lambda : ℝ) (hK : Kᵀ = K) :
    (regularizedKernelMatrix K lambda)ᵀ = regularizedKernelMatrix K lambda

lemma dyadicNets_nonempty {s : Set A} (hsne : s.Nonempty) {D : ℝ}
    (dn : DyadicNets s D) (k : ℕ) :
    (dn.nets k).Nonempty

lemma exists_near_in_net {t : Finset A} {eps : ℝ} {s : Set A}
    (hnet : IsENet t eps s) {x : A} (hx : x ∈ s) :
    ∃ y ∈ t, dist x y ≤ eps

theorem confidence_width_pos {H : ℕ} {B δ : ℝ}
    (hH : 0 < H) (hB : 0 < B) (hδ : 0 < δ) (hδ1 : δ < 1) :
    0 < B * Real.sqrt (2 * H * Real.log (1 / δ))

theorem chainingWeight_mono (A : AdmissibleSequence) {i j : Fin A.depth}
    (h : i.val ≤ j.val) :
    A.chainingWeight i ≤ A.chainingWeight j

theorem gamma2FiniteBound_nonneg {cardT : ℕ} {diamT C : ℝ}
    (hC : 0 ≤ C) (hD : 0 ≤ diamT) :
    0 ≤ gamma2FiniteBound cardT diamT C

theorem linearRademacherBound_anti {W X : ℝ} {n₁ n₂ : ℕ}
    (hW : 0 < W) (hX : 0 < X) (hn₁ : 0 < n₁) (h : n₁ ≤ n₂) :
    linearRademacherBound W X n₂ ≤ linearRademacherBound W X n₁

theorem symmetrization_vc_pac_width (d n : ℕ) (_hn : 1 ≤ n) (_hd : 1 ≤ d)
    (δ : ℝ) (_hδ : 0 < δ) (_hδ1 : δ < 1) :
    let R_bound := Real.sqrt (2 * (Real.log (d + 1 : ℝ) + d * Real.log (n : ℝ)) / n)
    let t := Real.sqrt (2 * Real.log (1 / δ) / n)
    0 ≤ 2 * R_bound + t

theorem le_cam_fano_comparison
    (Delta I : ℝ) (_hDelta : 0 < Delta) (_hI : 0 ≤ I)
    (_hI_small : I < Real.log 2) :
    let fano_bound := Delta * (1 - (I + Real.log 2) / Real.log 2)
    let le_cam_style := -(Delta * I / Real.log 2)
    fano_bound = le_cam_style
